    dp_path_not_0[0][0] = 0; // Cost 0 to not select element 0
    dp_path_not_0[0][1] = INF; // Cannot select element 0 in this case

    for (let i = 1; i < n; i++) {
        // State 0: Element i is NOT selected. We can transition from i-1 being selected or not selected.
        dp_path_not_0[i][0] = Math.min(dp_path_not_0[i - 1][0], dp_path_not_0[i - 1][1]);

        // State 1: Element i IS selected. Element i-1 MUST NOT be selected.
        dp_path_not_0[i][1] = dp_path_not_0[i - 1][0] + costs[i];
    }

    // Result for Case 1 (0 not selected): Minimum cost among the last element not being selected or being selected.
    let min_cost_case1 = Math.min(dp_path_not_0[n - 1][0], dp_path_not_0[n - 1][1]);


    // Case 2: Element 0 IS selected. (Solve for a path graph 1 to n-1, with constraint on 1)
    // dp_path_is_0[i][state]
    const dp_path_is_0: [number, number][] = [];
    for (let i = 0; i < n; i++) {
        dp_path_is_0.push([INF, INF]);
    }

    // Base case i = 0 (since we are assuming 0 is selected)
    dp_path_is_0[0][0] = INF; // Cannot not select element 0 in this case
    dp_path_is_0[0][1] = costs[0]; // Cost of selecting element 0

    for (let i = 1; i < n; i++) {
        // State 0: Element i is NOT selected. We can transition from i-1 being selected or not selected.
        dp_path_is_0[i][0] = Math.min(dp_path_is_0[i - 1][0], dp_path_is_0[i - 1][1]);

        // State 1: Element i IS selected. Element i-1 MUST NOT be selected.
        dp_path_is_0[i][1] = dp_path_is_0[i - 1][0] + costs[i];
    }

