    const dp_not_selected: number[][] = Array(n).fill(0).map(() => Array(M + 1).fill(INF_COST));
    // dp_selected[i][j]
    const dp_selected: number[][] = Array(n).fill(0).map(() => Array(M + 1).fill(INF_COST));

