            }
        }
    }

    // Final result for Case 2 (0 selected): n-1 MUST NOT be selected (due to circular constraint)
    const cost2 = dp2_not_selected[n - 1][k];

    finalMinCost = Math.min(cost1, cost2);


    if (finalMinCost >= INF_COST) {
        return -1;
    }

