 * Checks if an index i is a peak in the circular array nums.
 * @param nums The circular array.
 * @param i The index to check.
 * @returns True if nums[i] is a peak, false otherwise.
 */
function isPeak(nums: number[], i: number): boolean {
    const n = nums.length;
    // Get neighbors in a circular manner
    const prev = nums[(i - 1 + n) % n];
    const next = nums[(i + 1) % n];
    // Check if nums[i] is strictly greater than both neighbors
    return nums[i] > prev && nums[i] > next;
}

/**
 * Checks if it is possible to have at least k peaks in the given array.
 * In a circular array, the maximum number of peaks is floor(n/2).
 * If k > floor(n/2), it's impossible.
 * @param n The length of the array.
 * @param k The required minimum number of peaks.
 * @returns True if possible, false otherwise.
 */
function isPossible(n: number, k: number): boolean {
    if (k === 0) return true;
    // In a circular array, peaks must alternate with valleys (or non-peaks).
    // The maximum number of peaks is floor(n/2).
    return k <= Math.floor(n / 2);
}


